// src/pages/ProductDetails.js
import { useParams } from "react-router-dom";
import { useState } from "react";
import products from "../data/ProductData";

function ProductDetails() {
  const { id } = useParams();
  const product = products.find((p) => p.id === parseInt(id));

  if (!product) {
    return <h2 className="text-center mt-10">Product Not Found</h2>;
  }

  // handle multiple images (main + gallery)
  const images = [product.image, ...(product.images || [])];
  const [mainImage, setMainImage] = useState(images[0]);

  return (
    <div className="max-w-6xl mx-auto p-8 grid md:grid-cols-2 gap-10">
      {/* Left - Product Images */}
      <div className="flex flex-col items-center">
        {/* Main Image Container */}
        <div className="w-[150px] h-[150px] flex items-center justify-center border rounded-lg shadow">
          <img
            src={mainImage}
            alt={product.name}
            className="max-w-full max-h-full object-contain"
          />
        </div>

        {/* Thumbnails */}
        <div className="flex gap-3 mt-4 flex-wrap justify-center">
          {images.map((img, idx) => (
            <div
              key={idx}
              className={`w-[70px] h-[70px] flex items-center justify-center border rounded cursor-pointer ${
                mainImage === img ? "ring-2 ring-blue-500" : ""
              }`}
              onClick={() => setMainImage(img)}
            >
              <img
                src={img}
                alt={'${product.name}-${idx}'}
                className="max-w-full max-h-full object-contain"
              />
            </div>
          ))}
        </div>
      </div>

      {/* Right - Product Details */}
      <div>
        <h1 className="text-2xl font-bold mb-2">{product.name}</h1>
        <p className="text-gray-600 mb-4">{product.description}</p>

        <div className="flex items-center mb-4">
          <span className="text-2xl font-bold text-blue-600">
            ${product.offerPrice || product.price}
          </span>
          {product.offerPrice && (
            <span className="ml-3 text-gray-400 line-through">
              ${product.price}
            </span>
          )}
        </div>

        <div className="mb-4">
          <p>
            <strong>Brand:</strong> {product.brand || "Generic"}
          </p>
          <p>
            <strong>Color:</strong> {product.color || "Multi"}
          </p>
          <p>
            <strong>Category:</strong> {product.category}
          </p>
        </div>

        <div className="flex gap-4">
          <button className="bg-blue-600 text-white px-6 py-2 rounded-lg shadow hover:bg-blue-700">
            Add to Cart
          </button>
          <button className="bg-orange-500 text-white px-6 py-2 rounded-lg shadow hover:bg-orange-600">
            Buy Now
          </button>
        </div>
      </div>
    </div>
  );
}

export default ProductDetails;
